bool isBusy = false;
void SafeRead() {
    if (isBusy) { Print("设备忙，放弃读取"); return; }
    isBusy = true;
    Print($"读取: {Plc.ReadHoldingRegister(100)}");
    isBusy = false;
}

SafeRead();
// 模拟并发：不重置isBusy
isBusy = true;
SafeRead();
SafeRead();
isBusy = false;
